package com.pickleball.application.usecases.player; import com.pickleball.application.dtos.EloHistoryDTO; import com.pickleball.domain.repositories.EloHistoryRepository; import lombok.RequiredArgsConstructor; import java.util.List; import java.util.stream.Collectors; @RequiredArgsConstructor public class GetEloHistoryUseCase { private final EloHistoryRepository eloHistoryRepository; public List<EloHistoryDTO> execute(Long userId) { return eloHistoryRepository.findByUserId(userId).stream().map(h -> EloHistoryDTO.builder().id(h.getId()).rankedMatchId(h.getRankedMatchId()).seasonId(h.getSeasonId()).eloBefore(h.getEloBefore()).eloChange(h.getEloChange()).eloAfter(h.getEloAfter()).createdAt(h.getCreatedAt()).build()).collect(Collectors.toList()); } }
